def classify_beta_transition(beta_spin, neutrino_spin, orbital_angular_momentum=0):
    total_spin = beta_spin + neutrino_spin
    if orbital_angular_momentum == 0:
        if total_spin == 0:
            return "Fermi transition"
        elif total_spin == 1:
            return "Gamow-Teller transition"
    return "Forbidden transition (with orbital angular momentum)"

# Example usage:
print(classify_beta_transition(0.5, -0.5))  # Output: Fermi transition
print(classify_beta_transition(0.5, 0.5))   # Output: Gamow-Teller transition
print(classify_beta_transition(0.5, 0.5, 1)) # Output: Forbidden transition (with orbital angular momentum)
